export const getGetTopRiskUsersUrl = (params?: GetTopRiskUsersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/analytics/top-risk-users?${stringifiedParams}` : `/api/analytics/top-risk-users`
}

